commands_run.command:
node - <<'NODE'
const fs=require('fs');
const path=require('path');
const base='evals/effectiveness/reports/refactor-small-001';
const run='evals/effectiveness/runs/refactor-small-001/treatment/target-repo';
const readJson=p=>fs.existsSync(p)?JSON.parse(fs.readFileSync(p,'utf8')):null;
const state=readJson(path.join(base,'treatment-generic-refactor-state.json'));
let evaluatorOutput=null;
let evaluatorOutputFound=false;
let evaluatorVerdict='';
const stdoutPath=path.join(base,'sdk-stage-logs/generic-refactor-evaluator-stdout.log');
if (fs.existsSync(stdoutPath)) {
  try {
    evaluatorOutput=JSON.parse(fs.readFileSync(stdoutPath,'utf8'));
    evaluatorOutputFound=true;
    evaluatorVerdict=evaluatorOutput.verdict || evaluatorOutput.status || '';
  } catch {}
}
const candidates=[
  path.join(run,'artifacts/eval-report.json'),
  path.join(run,'artifacts/final-eval-report.json'),
  path.join(base,'sdk-stage-logs/generic-refactor-evaluator-stdout.log')
];
const evaluatorArtifactPathsFound=candidates.filter(p=>fs.existsSync(p));
const evalReportPath=fs.existsSync(path.join(run,'artifacts/eval-report.json'))?'artifacts/eval-report.json':'';
const finalReportPath=fs.existsSync(path.join(run,'artifacts/FinalDeliveryReport.md'))?'artifacts/FinalDeliveryReport.md':'';
const validationLog=fs.existsSync(path.join(base,'treatment-validation.log'))?fs.readFileSync(path.join(base,'treatment-validation.log'),'utf8'):'';
const validationPassed=/Refactor behavior contract satisfied\.|Refactor structure contract satisfied\./.test(validationLog) && /pass 4/.test(validationLog);
const directPassApplicable=evaluatorVerdict==='PASS' && Boolean(state?.planner?.thread_id && state?.dev_worker?.thread_id && state?.evaluator?.thread_id && validationPassed);
const repairPathRequired=evaluatorVerdict==='NEEDS_REVISION';
const triage={
  case_id:'refactor-small-001',
  treatment_real_run_executed:Boolean(state?.planner?.thread_id || state?.dev_worker?.thread_id || state?.evaluator?.thread_id),
  treatment_status:'BLOCKED',
  planner_thread_id_present:Boolean(state?.planner?.thread_id),
  dev_worker_thread_id_present:Boolean(state?.dev_worker?.thread_id),
  initial_evaluator_thread_id_present:Boolean(state?.evaluator?.thread_id),
  validation_passed:validationPassed,
  evaluator_artifact_paths_found:evaluatorArtifactPathsFound,
  evaluator_output_found:evaluatorOutputFound,
  evaluator_verdict_detected:evaluatorVerdict,
  eval_report_path:evalReportPath,
  final_report_path:finalReportPath,
  direct_pass_path_applicable:directPassApplicable,
  repair_path_required:repairPathRequired,
  artifact_mapping_issue_detected:evaluatorOutputFound && !evalReportPath,
  final_report_generation_possible_from_existing_evidence:directPassApplicable && !finalReportPath,
  requires_treatment_rerun:!directPassApplicable,
  recommended_fixes: directPassApplicable ? [
    'Generate FinalDeliveryReport from existing direct PASS evidence and update treatment-result.json without running SDK.'
  ] : [
    'Persist evaluator-lite output to artifacts/eval-report.json for generic refactor evaluator stages.',
    'Return a structured BLOCKED treatment result instead of throwing when evaluator artifact recovery fails.',
    'After dry validation, request approval for exactly one refactor-small-001 treatment-only fresh rerun; do not rerun baseline unless approved.'
  ]
};
fs.mkdirSync(base,{recursive:true});
fs.writeFileSync(path.join(base,'refactor-evaluator-artifact-triage.json'), JSON.stringify(triage,null,2)+'\n');
fs.writeFileSync(path.join(base,'RefactorEvaluatorArtifactTriageReport.md'), [
  '# Refactor Evaluator Artifact Triage',
  '',
  `- Case: ${triage.case_id}`,
  `- Treatment real run executed: ${triage.treatment_real_run_executed}`,
  `- Planner thread id present: ${triage.planner_thread_id_present}`,
  `- Dev worker thread id present: ${triage.dev_worker_thread_id_present}`,
  `- Initial evaluator thread id present: ${triage.initial_evaluator_thread_id_present}`,
  `- Validation passed: ${triage.validation_passed}`,
  `- Evaluator output found: ${triage.evaluator_output_found}`,
  `- Evaluator verdict detected: ${triage.evaluator_verdict_detected || 'none'}`,
  `- EvalReport artifact path: ${triage.eval_report_path || 'missing'}`,
  `- Direct PASS path applicable: ${triage.direct_pass_path_applicable}`,
  `- Repair path required: ${triage.repair_path_required}`,
  `- Requires treatment rerun: ${triage.requires_treatment_rerun}`,
  '',
  '## Recommendation',
  '',
  ...triage.recommended_fixes.map(x=>`- ${x}`),
  ''
].join('\n'));
console.log(JSON.stringify(triage,null,2));
NODE
